  ('customs-41d95f20-moex-00050', 'customs-41d95f20', 'customs-41d95f20-moex-113-1400d907', 'sub-customs-41d95f20-01', NULL, 'essay', '中譯英：請將下列中文句子譯成英文。（15 分）
臺灣過去的發展完全仰賴成本優勢，政策手段不出降低稅負、補貼油電、
壓低勞動條件、犧牲環境品質，以及為了特定產業的出口配額或關稅而
犧牲其他產業。這些補貼手段培養出各級產業競逐下游的惰性，壓榨員
工勞力，還成為政府財政嚴重惡化的元兇。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:12+00:00", "source_pdf_sha1": "764467943ad6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "102", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "外國文(英文)", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "關稅法務"}'::jsonb, NULL),
  ('customs-41d95f20-moex-00051', 'customs-41d95f20', 'customs-41d95f20-moex-113-1400d907', 'sub-customs-41d95f20-01', NULL, 'essay', '英文作文：（20分）
